#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    ret = GetBlur1(texture(sampler_pw_main, fract(vUvOriginal)));

    float retx = (1 - ret.x)*(1 - ret.y)*(1 - ret.z);

    vec2 d = -6*pow(q25, .3)*uTexSize.zw*(2.5*pow(retx, .333)*sqrt(q23)
               + .04*sqrt(q21)*lum(GetBlur2(ret))
               + .0333*floor(1.25*sqrt(q32)*pow(GetBlur3(ret.x)*GetBlur3(ret.y)*GetBlur3(ret.z), .333)));

    vec3 dx = ( GetBlur1(vUvOriginal + vec2(1,0)*d) - GetBlur1(vUvOriginal-vec2(1,0)*d) );
    vec3 dy = ( GetBlur1(vUvOriginal + vec2(0,1)*d) - GetBlur1(vUvOriginal-vec2(0,1)*d) );

    vec2 uv_dy = vUvOriginal
        + (.3*vec2(lum(dx), lum(dy))
        - .1*(vec2(dx.x, dy.x)*sqrt(q21)
              + vec2(dx.y, dy.y)*sqrt(q23)
              + vec2(dx.z, dy.z)*sqrt(.1*q27)))*uTexSize.zw*6*sqrt(q5);

    ret = GetPixel(uv_dy) - (ret
        - vec3(sqrt(audioLowSmooth*(1 - GetPixel(vUvOriginal).y)*(1 - GetPixel(vUvOriginal).z)),
                 sqrt(audioMidSmooth*(1 - GetPixel(vUvOriginal).x)*(1 - GetPixel(vUvOriginal).z)),
                 sqrt(audioHighSmooth*(1 - GetPixel(vUvOriginal).x)*(1 - GetPixel(vUvOriginal).y))) )*0.0014*pow(q25, .2);

    ret = mix(ret.xyz,
               q22*texture(sampler_pc_main, vUvOriginal).xyz,
               .1*vec3(audioLowSmooth, audioMidSmooth, audioHighSmooth));
    ret = mix(ret,
               mix(texture(sampler_pc_main, vUv),
                    texture(sampler_pw_main, fract(vUv)),
                    clamp01(q6 - .9*pow(q8, .3))),
               (q6*lum(pow(vec3(ret.x, ret.y, 1.3*ret.z) + .15, pow(q23, .25))))> pow(q8, .3));
    ret += .00667*(pow(q3, .667) - .25)*texture( sampler_pw_main, fract(vUvOriginal) );

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


    uva = (vUv-0.5)*uAspect.xy + .5;
    float moon = (pow(q24, .333) / length(uva-moonpos));

    dz.x = lum(GetPixel(vUv-hor)) - lum(GetPixel(vUv+hor));
    dz.y = lum(GetPixel(vUv-ver)) - lum(GetPixel(vUv+ver));

    vec3 shine = GetPixel(vUv*.95 + .025);
    uv2 = (vUv-moonpos)*1.4 + moonpos;

    radi = q10;

    for (int n=1; n <= anz; n++)
    {
      uv2 = (normalize(vUv-moonpos)*radi+moonpos);
      shine += 2.5/anz*Get1((vUv-moonpos)*radi+moonpos,radi) ;
      radi -= 0.75/anz;;
    }


    vec2 uv_temp1 = (vUv - 0.5) * uTexSize.xy;
    vec2 c = ((vUv-0.5)*uAspect.wz);
    float rad_hq = length(uv_temp1);
    float ang_hq = atan(c.x,-c.y);

    uv2 = (uv2-0.5);
    float rad2 = rad_hq*.85;
    float ang2 = ang_hq * M_INV_PI_2;

        // FIN TYPE
        float fins = (q26 + 5);
        ang2 = fract(ang2*fins)/fins;
              // ENABLE THIS TO MAKE THE FINS ALTERNATE: (seamless!)
              ang2 = abs(ang2 - 0.5/fins);

    ang2 *= M_PI_2;
    vUv = 0.5 + rad2*vec2(cos(ang2),sin(ang2))*uTexSize.zw;

    ret = pow(GetBlur1(vUv)*((texture(sampler_pc_main,vUv)-GetBlur2(vUv))), .667*sqrt(q31)); //invert
    vec3 ret_t = refract(max(-sqrt(.45 + .25*q11)*shine, pow(GetPixel(vUv), pow(.4/q24, .15)) + .05), (pow(GetPixel(vUv), lum(exp(shine)))), .7 + .3*abs(q13)*sign(q13));
    vec3 ret_s = min(pow(pow(q23, .333), -shine), -pow(GetPixel(vUv), pow(.333*q31, .2)*shine) );
    vec3 ret_r = refract(ret_t, -ret_s, .8 + .2*abs(q12)*sign(q12));

    ret_s = mix(ret_t, (ret_s), mix(max(pow(.3*q27, .2)*shine, -shine), min(shine, pow(ret, ang2))/pow(q9, .125), -ret_r*pow(.333*q31, .2)));
    ret = (-mix(max(pow(cross((pow(.5/pow(q1, .05), ret_r)), pow(.5/pow(q8, .05), ret_s)), 1/pow(q23, .075)), pow(1-exp(-ret_s), pow(q25, .125))), mix(ret_t, ret_r, ret_s), pow(max(shine, -shine) , min(shine, -shine)) ));


  fragColor = ret;
}
